private function Auditor_SyncSingleUser($sToken)
{
    $iUserId = $this->Get('user');
    $oUser = MetaModel::GetObject('UserExternal', $iUserId, false);
    if (!$oUser) {
        throw new Exception('UserExternal not found for id '.$iUserId);
    }

    $sUsername = $oUser->Get('login');
    if (empty($sUsername)) {
        throw new Exception('UserExternal '.$iUserId.' has empty login');
    }

    $sTenantName = 'Default';
    $iTenantId = 0;
    $iContactId = $oUser->Get('contactid');
    if (!empty($iContactId)) {
        $oPerson = MetaModel::GetObject('Person', $iContactId, false);
        if ($oPerson) {
            $iOrgId = $oPerson->Get('org_id');
            if (!empty($iOrgId)) {
                $oOrg = MetaModel::GetObject('Organization', $iOrgId, false);
                if ($oOrg) {
                    $sTenantName = $oOrg->GetName();
                    $iTenantId = (int) $oOrg->Get('auditor_tenant_id');
                }
            }
        }
    }

    if ($iTenantId <= 0) {
        throw new Exception('Tenant is not synchronized with auditor-service for organization '.$sTenantName);
    }

    $sTempPwd = bin2hex(random_bytes(8));

    if (UserRights::IsAdministrator()) {
        $sRole = 'ADMIN';
    } else {
        $sRole = 'AUDITOR';
    }

    $aBody = array(
        'username' => $sUsername,
        'temporaryPassword' => $sTempPwd,
        'role' => $sRole,
        'tenantId' => $iTenantId,
        'itopUserExternalId' => $iUserId,
    );

    $sBaseUrl = getenv('AUDITOR_SERVICE_URL') ?: 'http://auditor-service:8081';
    $sUrl = rtrim($sBaseUrl, '/').'/api/users/internal';

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('auditor-service createUserFromItop failed: '.curl_error($ch));
    }
    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($iStatus !== 201 && $iStatus !== 200) {
        throw new Exception('auditor-service createUserFromItop HTTP '.$iStatus.': '.$sResult);
    }

    $mData = json_decode($sResult, true);
    if (is_array($mData)) {
        $iAuditorUserId = (int) reset($mData);
    } else {
        $iAuditorUserId = (int) $sResult;
    }

    if ($iAuditorUserId > 0) {
        $oMappingSet = new DBObjectSet(
            DBObjectSearch::FromOQL('SELECT AuditUserMapping WHERE user = :uid'),
            array(),
            array('uid' => $iUserId)
        );
        $oMapping = $oMappingSet->Fetch();

        if ($oMapping) {
            $oMapping->Set('auditor_user_id', $iAuditorUserId);
            $oMapping->AllowWrite();
            $oMapping->DBUpdate();
        } else {
            $oMapping = MetaModel::NewObject('AuditUserMapping');
            $oMapping->Set('user', $iUserId);
            $oMapping->Set('auditor_user_id', $iAuditorUserId);
            $oMapping->DBInsert();
        }
    }

    $_SESSION['audit_user_temp_password_once'] = array(
        'job_id' => $this->GetKey(),
        'username' => $sUsername,
        'tenant_name' => $sTenantName,
        'password' => $sTempPwd,
    );
}

public function GetFilterFor($sAttCode)
{
    if ($sAttCode === 'agent') {
        $iOrgId = 0;
        $oUser = UserRights::GetUserObject();
        if ($oUser) {
            $iContactId = $oUser->Get('contactid');
            if (!empty($iContactId)) {
                $oPerson = MetaModel::GetObject('Person', $iContactId, false);
                if ($oPerson) {
                    $iOrgId = (int) $oPerson->Get('org_id');
                }
            }
        }
        if ($iOrgId > 0) {
            return DBObjectSearch::FromOQL('SELECT AuditAgent WHERE organization = :org', array(), array('org' => $iOrgId));
        }
    }
    return parent::GetFilterFor($sAttCode);
}

